def parse_exchange_file(path, default_compartment):
    context = FilePathContext(path)

    def is_valid_entry(entry):
        compound = entry.get('compound')
        if not compound or not str(compound).isalnum():
            return False
        try:
            lower = float(entry['lower'])
            upper = float(entry['upper'])
            if lower > upper:
                return False
        except (ValueError, KeyError, TypeError):
            return False
        return True

    # Detect format based on content
    detected_format = None
    try:
        with context.open('r') as f:
            # Handle BOM and empty files
            content = f.read()
            if content.startswith('\ufeff'):
                content = content[1:]

            lines = [line.strip() for line in content.splitlines() if line.strip() and not line.strip().startswith('#')]

            if not lines:
                return # Empty or whitespace-only file

            # Check first non-comment line for format
            first_line = lines[0]
            if '\t' in first_line or 'compound' in first_line.lower():
                detected_format = 'tsv'
            elif ':' in first_line:
                detected_format = 'yaml'
    except Exception as e:
        raise ParseError(f"Could not read file for format detection: {e}")

    if not detected_format:
        # Fallback to extension if content is ambiguous
        detected_format = resolve_format(None, context.filepath)

    if not detected_format:
        raise ParseError("Could not determine file format.")

    # Re-open and parse
    try:
        with context.open('r') as f:
            content = f.read()
            if content.startswith('\ufeff'):
                content = content[1:]

            # Create a generator for filtered lines
            def filtered_lines(text):
                for line in text.splitlines():
                    s_line = line.strip()
                    if s_line and not s_line.startswith('#'):
                        yield line

            import io
            f_filtered = io.StringIO('\n'.join(filtered_lines(content)))

            if detected_format == 'tsv':
                # Skip header if present
                first_line = f_filtered.readline()
                if 'compound' not in first_line.lower() and first_line.strip():
                    # If first line isn't a header, we need to process it
                    f_filtered.seek(0)

                for entry in parse_exchange_table_file(f_filtered):
                    if is_valid_entry(entry):
                        yield entry
            elif detected_format == 'yaml':
                for entry in parse_exchange_yaml_file(context, f_filtered, default_compartment):
                    if is_valid_entry(entry):
                        yield entry
    except Exception as e:
        if isinstance(e, ParseError):
            raise
        logger.error(f"Error parsing file: {e}")
